#include<stdio.h>
#define INF 2000000
int v[1001],l[1001],r[1001];
int check(int u,int lo,int hi){
  if(u<0)return 1;
  if(v[u]<=lo||v[u]>=hi)return 0;
  return check(l[u],lo,v[u])&&check(r[u],v[u],hi);
}
int main(){int n;scanf("%d",&n);for(int i=0;i<n;i++)scanf("%d",&v[i]);for(int i=0;i<n;i++)scanf("%d %d",&l[i],&r[i]);puts(check(0,-INF,INF)?"YES":"NO");}
